    invariant sorted.Length == n
    invariant forall p, q :: 0 <= p < q < i ==> sorted[p] <= sorted[q]
    invariant forall p, q :: 0 <= p < i && i <= q < n ==> sorted[p] <= sorted[q]
    invariant multiset(sorted[..]) == multiset(inputs[..])
    decreases n - i
  {
    var m := i;
    var j := i + 1;
    while j < n
      invariant i < n
      invariant i + 1 <= j <= n
      invariant i <= m < n
      invariant sorted.Length == n
