        var oldM := m;
        assert forall k | i <= k < j + 1 :: sorted[j] <= sorted[k] by {
          if k == j {
          } else {
            assert i <= k < j;
            assert sorted[oldM] <= sorted[k];
            assert sorted[j] <= sorted[oldM];
